#include<bits/stdc++.h>
using namespace std;
const long long nulltag=1145141919810;
long long b[100010];
struct segment_tree
{
    struct node
    {
        long long l,r,max1;
        long long lson,rson;
        long long add_tag,upd_tag;
        long long maxadd,maxupd,maxmax;
    }a[300010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].max1=max(a[a[x].lson].max1,a[a[x].rson].max1);
    }
    void pushupd(long long x,long long v,long long maxv)
    {
        a[x].upd_tag=v;
        a[x].maxupd=max(a[x].maxupd,maxv);
        a[x].max1=v;
        a[x].maxmax=max(a[x].maxmax,maxv);
    }
    void pushadd(long long x,long long v,long long maxv)
    {
        if(a[x].upd_tag!=nulltag)
        {
            pushupd(x,a[x].upd_tag+v,a[x].upd_tag+maxv);
            return;
        }
        a[x].maxadd=max(a[x].maxadd,a[x].add_tag+maxv);
        a[x].add_tag+=v;
        a[x].max1+=v;
        a[x].maxmax=max(a[x].maxmax,a[x].max1-a[x].add_tag+a[x].maxadd);
    }
    void pushdown(long long x)
    {
        pushadd(a[x].lson,a[x].add_tag,a[x].maxadd);
        pushadd(a[x].rson,a[x].add_tag,a[x].maxadd);
        a[x].add_tag=0;
        a[x].maxadd=0;
        if(a[x].upd_tag!=nulltag)
        {
            pushupd(a[x].lson,a[x].upd_tag,a[x].maxupd);
            pushupd(a[x].rson,a[x].upd_tag,a[x].maxupd);
            a[x].upd_tag=nulltag;
        }
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        a[x].add_tag=0;
        a[x].upd_tag=nulltag;
        a[x].maxupd=-1e18;
        if(l==r)
        {
            a[x].max1=a[x].maxmax=b[l];
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void add(long long x,long long l,long long r,long long z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            pushadd(x,z,max(0ll,z));
            return;
        }
        pushdown(x);
        add(a[x].lson,l,r,z);
        add(a[x].rson,l,r,z);
        pushup(x);
    }
    void update(long long x,long long l,long long r,long long z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            pushupd(x,z,z);
            return;
        }
        pushdown(x);
        update(a[x].lson,l,r,z);
        update(a[x].rson,l,r,z);
        pushup(x);
    }
    long long getmax(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return -1e18;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].max1;
        }
        pushdown(x);
        return max(getmax(a[x].lson,l,r),getmax(a[x].rson,l,r));
    }
    long long gethmax(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return -1e18;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].maxmax;
        }
        pushdown(x);
        return max(gethmax(a[x].lson,l,r),gethmax(a[x].rson,l,r));
    }
}t;
int main()
{
    long long n;
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
    }
    t.init(1,n);
    long long q;
    scanf("%lld",&q);
    while(q--)
    {
        char op;
        long long x,y,z;
        cin>>op;
        scanf("%lld%lld",&x,&y);
        if(op=='Q')
        {
            printf("%lld\n",t.getmax(1,x,y));
        }
        else if(op=='A')
        {
            printf("%lld\n",t.gethmax(1,x,y));
        }
        else if(op=='P')
        {
            scanf("%lld",&z);
            t.add(1,x,y,z);
        }
        else
        {
            scanf("%lld",&z);
            t.update(1,x,y,z);
        }
    }
    return 0;
}
